const staticData = $getWorkflowStaticData('global');
const sinceToken = staticData.sinceToken || '';
const homeserver = $env.MATRIX_HOMESERVER;
const todoRoom = $env.MATRIX_ROOM_TODO;
const botToken = $env.MATRIX_BOT_TOKEN;

if (!homeserver || !todoRoom || !botToken) {
  return [{ json: { error: 'Matrix config missing', skip: true } }];
}

const filter = JSON.stringify({
  room: {
    rooms: [todoRoom],
    timeline: { types: ['m.room.message'], limit: 20 }
  },
  presence: { types: [] },
  account_data: { types: [] }
});

let syncUrl = `${homeserver}/_matrix/client/v3/sync?timeout=0&filter=${encodeURIComponent(filter)}`;
if (sinceToken) {
  syncUrl += `&since=${encodeURIComponent(sinceToken)}`;
}

return [{
  json: {
    syncUrl,
    isFirstRun: !sinceToken,
    todoRoom
  }
}];

const staticData = $getWorkflowStaticData('global');
const syncResp = $input.first().json;
const prevData = $('准备同步').first().json;
const isFirstRun = prevData.isFirstRun;
const todoRoom = prevData.todoRoom;

// Save next_batch token
if (syncResp.next_batch) {
  staticData.sinceToken = syncResp.next_batch;
}

// First run: just save token, don't process
if (isFirstRun) {
  return [{ json: { skip: true } }];
}

// Check for errors
if (syncResp.errcode) {
  return [{ json: { skip: true, error: syncResp.error } }];
}

const commands = [];
const joinedRooms = syncResp.rooms?.join || {};

for (const [roomId, roomData] of Object.entries(joinedRooms)) {
  if (roomId !== todoRoom) continue;
  const events = roomData.timeline?.events || [];

  for (const event of events) {
    if (event.type !== 'm.room.message') continue;
    const body = (event.content?.body || '').trim();

    // Support both ! and ！ (full-width)
    if (!body.startsWith('!') && !body.startsWith('！')) continue;

    const parts = body.substring(1).trim().split(/\s+/);
    const cmd = parts[0];
    const args = parts.slice(1).join(' ');

    let command = null;

    switch(cmd) {
      case '\u5f85\u529e':
      case '\u5217\u8868':
      case '\u5f85\u529e\u5217\u8868':
      case '\u67e5\u8be2':
      case '\u67e5\u770b':
        command = { action: 'list' };
        break;
      case '\u65b0\u589e':
      case '\u6dfb\u52a0':
        if (args) {
          // Parse priority: !新增 P1 text or !新增 text
          const pMatch = args.match(/^P(\d)\s+(.+)/);
          if (pMatch) {
            command = { action: 'add', text: pMatch[2], priority: parseInt(pMatch[1]) };
          } else {
            command = { action: 'add', text: args, priority: 3 };
          }
        }
        break;
      case '\u5b8c\u6210':
        if (args) command = { action: 'done', memo_name: `memos/${args}` };
        break;
      case '\u5220\u9664':
        if (args) command = { action: 'delete', memo_name: `memos/${args}` };
        break;
      case '\u4fee\u6539':
        // Format: !修改 <id> <new text>
        const modParts = args.split(/\s+/);
        if (modParts.length >= 2) {
          command = { action: 'modify', memo_name: `memos/${modParts[0]}`, text: modParts.slice(1).join(' ') };
        }
        break;
      case '\u5e2e\u52a9':
      case 'help':
        command = { action: 'help' };
        break;
    }

    if (command) {
      command.sender = event.sender;
      commands.push(command);
    }
  }
}

if (commands.length === 0) {
  return [{ json: { skip: true } }];
}

return commands.map(cmd => ({ json: cmd }));

const response = $input.first().json;
const command = $('逐个处理').first().json;
const action = command.action;

let message = '';

if (response.success === false || response.error) {
  message = `\u274c \u64cd\u4f5c\u5931\u8d25: ${response.error || '\u672a\u77e5\u9519\u8bef'}`;
} else {
  switch(action) {
    case 'list': {
      const memos = response.memos || [];
      if (memos.length === 0) {
        message = '\ud83d\udcdd \u5f53\u524d\u6ca1\u6709\u5f85\u529e\u4e8b\u9879';
      } else {
        const lines = ['\ud83d\udcdd \u5f85\u529e\u5217\u8868:'];
        memos.forEach((memo, i) => {
          const content = memo.content || '';
          const text = content.replace(/#\S+/g, '').trim();
          const id = (memo.name || '').replace('memos/', '');
          const priority = (content.match(/#P(\d)/) || [])[1] || '-';
          lines.push(`${i + 1}. [#${id}] P${priority} ${text}`);
        });
        message = lines.join('\n');
      }
      break;
    }
    case 'add':
      message = `\u2795 \u5df2\u6dfb\u52a0\u5f85\u529e: ${command.text}`;
      break;
    case 'done':
      message = `\u2705 \u5df2\u5b8c\u6210\u5f85\u529e: ${command.memo_name}`;
      break;
    case 'delete':
      message = `\ud83d\uddd1\ufe0f \u5df2\u5220\u9664\u5f85\u529e: ${command.memo_name}`;
      break;
    case 'modify':
      message = `\u270f\ufe0f \u5df2\u4fee\u6539\u5f85\u529e: ${command.text}`;
      break;
    default:
      message = `\u2753 \u672a\u77e5\u64cd\u4f5c: ${action}`;
  }
}

return [{ json: { room: 'todo', message } }];

const data = $input.first().json;
const memos = data.memos || [];

const now = new Date();
const dateStr = `${now.getFullYear()}-${String(now.getMonth() + 1).padStart(2, '0')}-${String(now.getDate()).padStart(2, '0')}`;

let message = '';

if (memos.length === 0) {
  message = `\ud83c\udf05 \u65e9\u5b89! ${dateStr}\n\n\u2728 \u4eca\u65e5\u6ca1\u6709\u5f85\u529e\u4e8b\u9879\uff0c\u4eab\u53d7\u7f8e\u597d\u7684\u4e00\u5929!`;
} else {
  const lines = [`\ud83c\udf05 \u65e9\u5b89! ${dateStr}`, '', `\ud83d\udcdd \u4eca\u65e5\u5f85\u529e (${memos.length} \u9879):`];

  // Sort by priority
  const sorted = memos.sort((a, b) => {
    const pA = parseInt((a.content?.match(/#P(\d)/) || [])[1] || '3');
    const pB = parseInt((b.content?.match(/#P(\d)/) || [])[1] || '3');
    return pA - pB;
  });

  sorted.forEach((memo, i) => {
    const content = memo.content || '';
    const text = content.replace(/#\S+/g, '').trim();
    const id = (memo.name || '').replace('memos/', '');
    const priority = (content.match(/#P(\d)/) || [])[1] || '3';
    const pEmoji = priority === '1' ? '\ud83d\udd34' : priority === '2' ? '\ud83d\udfe1' : '\u26aa';
    lines.push(`${pEmoji} ${i + 1}. [#${id}] ${text}`);
  });

  lines.push('', '\u53d1\u9001 !\u5e2e\u52a9 \u67e5\u770b\u6307\u4ee4\u7528\u6cd5');
  message = lines.join('\n');
}

return [{ json: { room: 'todo', message } }];
